body:
Thanks for taking the time to report this.

Can you please attach an example that shows the issue or missing feature?  (Must be openly licensed, completely self-contained so can directly run what you provide. Ideally use test_regress format, see https://veripool.org/guide/latest/contributing.html?highlight=test_regress#reporting-bugs)

```
module p_en_reg #( parameter type T = logic [31:0] )
(
  input  logic clk,
  input  logic en,
  input  T     in,
  output T     out
);
   always_ff @(posedge clk) begin
      if (en)
        out <= in;
   end
endmodule
module p_rst_reg #( parameter type T = logic [31:0])
(
  input  logic clk,
  input  logic rst_n,
  input  T     in,
  output T     out
);
   always_ff @(posedge clk or negedge rst_n) begin
      if (!rst_n)
        out <= '0;
      else
        out <= in;
   end
endmodule
module ring #(
  parameter int unsigned   N_IDS  = 5,          
  parameter type           DATA_T = logic[31:0]
) (
  input  logic             clk,
  input  logic             rst_n,
  input  logic             in_v,
  input  DATA_T            in_data,              
  output logic             out_v   [N_IDS-1:0],
  output DATA_T            out_data[N_IDS-1:0]
);
   p_rst_reg     #(.T(logic))  u_v_reg   (                .in(in_v),    .out(out_v   [0]), .* );
   p_en_reg      #(.T(DATA_T)) u_data_reg( .en(out_v[0]), .in(in_data), .out(out_data[0]), .* );
endmodule
module ring_chk #(
  parameter int unsigned   N_IDS  = 5,          
  parameter type           DATA_T = logic[31:0]
) (
  input  logic             clk,
  input  logic             rst_n,
  input  int unsigned      cycle,
  input  logic             in_v,
  input  DATA_T            in_data,              
  input  logic             out_v   [N_IDS-1:0],
  input  DATA_T            out_data[N_IDS-1:0]
);
   typedef logic [3-1:0] ID_T;
   localparam ID_T SRC_ID = '0;
   logic  in_v_d1;
   ID_T   in_id_d1 = '0;
   logic  out_v_d1[N_IDS-1:0];
   DATA_T expect_data[N_IDS-1:0][$];
   always_ff @(posedge clk or negedge rst_n) begin
     if (!rst_n) begin
       in_v_d1       <= '0;
       foreach (out_v_d1[i])
         out_v_d1[i] <= '0;
     end
     else begin
        in_v_d1       <= in_v;
        out_v_d1      <= out_v;
        if (in_v_d1) begin
           expect_data[in_id_d1].push_back(in_data);
           $display("t=%04t/%02d src=%02d dst=%02d sent     %p", $time, cycle, SRC_ID, in_id_d1, in_data);
        end
        foreach(out_v[k]) begin
           if (out_v_d1[k]) begin
              DATA_T expect_data_head;
              expect_data_head = expect_data[k].pop_front();
              $display( "t=%04t/%02d src=%02d dst=%02d received %p", $time, cycle, SRC_ID, k, out_data[k]);
              if (out_data[k] != expect_data_head)
                $fatal(1, "t=%04t/%02d src=%02d dst=%02d mismatch %p, expected %p", $time, cycle, SRC_ID, k, out_data[k], expect_data[k][0]);
         end
       end
     end  
   end
endmodule  
module tb_ring;
   localparam int N_IDS           = 5;
   typedef logic [31:0]     data_t;
   logic    clk, rst_n;
   int unsigned n_cycles      = 1;
   int unsigned cycle;
   logic  in_v;
   data_t in_data;
   logic  out_v   [N_IDS-1:0];
   data_t out_data[N_IDS-1:0];
   ring     dut ( .* );
   ring_chk chk ( .* );
   initial begin
      clk = '0;
      forever #5 clk = ~clk;
   end
   initial begin
      rst_n = '0;
      repeat (5) @(posedge clk);
      rst_n = '1;
      repeat (5) @(posedge clk);
      $display("test passed!");
      $finish;
   end  
   always_ff @(posedge clk or negedge rst_n)
     if (!rst_n) begin
        cycle <= '0;
        in_v  <= '0;
     end
     else begin
        cycle <= cycle + 1;
        if (cycle < n_cycles) begin
           in_v    <= '1;  
           in_data <= data_t'(cycle + 1);
        end
        else begin
           in_v    <= '0;
        end
     end  
endmodule
```

What output from that test indicates it is wrong, and what is the correct or expected output?  (Or, please make test self-checking if possible.)

Verilator:

```
verilator --binary -Wno-fatal --CFLAGS -fcoroutines -j 8 --top-module tb_ring test.sv && timeout 10s ./obj_dir/Vtb_ring
...
t=  65/02 src=00 dst=00 sent              1
t=  75/03 src=00 dst=00 received          1
[75] %Fatal: test.sv:78: Assertion failed in tb_ring.chk.unnamedblk2.unnamedblk3: t=  75/03 src=00 dst=00 mismatch          1, expected          0
%Error: test.sv:78: Verilog $stop
Aborting...
```

